"use client"

import * as React from "react"
import { ClubCardPreview } from "./club-card-preview"
import { ClubCardDrawer } from "./club-card-drawer"
import type { ClubCardProps, DrawerDirection } from "./types"

function useResolvedDirection(direction: DrawerDirection) {
  const [isDesktop, setIsDesktop] = React.useState(false)

  React.useEffect(() => {
    const mediaQuery = window.matchMedia("(min-width: 768px)")
    const sync = () => setIsDesktop(mediaQuery.matches)
    sync()
    mediaQuery.addEventListener("change", sync)
    return () => mediaQuery.removeEventListener("change", sync)
  }, [])

  return direction === "auto" ? (isDesktop ? "right" : "bottom") : direction
}

export function ClubCard({
  domain,
  name,
  imageUrl,
  miniDescription,
  shouldCompress = false,
  showSuccessIcon = false,
  ctaText,
  cardCtaText,
  drawerCtaText,
  onCtaClick,
  totalMembers,
  detailPoints,
  detailDescription,
  drawerDirection = "auto",
  ctaTheme,
}: ClubCardProps) {
  const [open, setOpen] = React.useState(false)
  const resolvedDirection = useResolvedDirection(drawerDirection)
  const resolvedCardCtaText = cardCtaText ?? ctaText
  const resolvedDrawerCtaText = drawerCtaText ?? ctaText

  const handleCtaClick = () => {
    setOpen(true)
  }

  return (
    <>
      <ClubCardPreview
        domain={domain}
        name={name}
        imageUrl={imageUrl}
        miniDescription={miniDescription}
        shouldCompress={shouldCompress}
        showSuccessIcon={showSuccessIcon}
        ctaText={resolvedCardCtaText}
        ctaTheme={ctaTheme}
        onCtaClick={handleCtaClick}
      />
      <ClubCardDrawer
        domain={domain}
        name={name}
        imageUrl={imageUrl}
        totalMembers={totalMembers}
        detailPoints={detailPoints}
        detailDescription={detailDescription}
        ctaText={resolvedDrawerCtaText}
        ctaTheme={ctaTheme}
        onCtaClick={onCtaClick}
        open={open}
        onOpenChange={setOpen}
        resolvedDirection={resolvedDirection}
      />
    </>
  )
}

export type { ClubCardProps, DrawerDirection, CtaTheme } from "./types"

import type { ClubCardProps } from "./types";
import { CardCtaButton } from "../shared/card-cta-button";
import { CheckCircle } from "@phosphor-icons/react";

function toCapitalizedWords(value: string) {
  return value.replace(/\b\w/g, (char) => char.toUpperCase());
}

type ClubCardPreviewProps = Pick<
  ClubCardProps,
  | "domain"
  | "name"
  | "imageUrl"
  | "miniDescription"
  | "shouldCompress"
  | "showSuccessIcon"
  | "ctaText"
  | "ctaTheme"
> & {
  onCtaClick: () => void;
};

export function ClubCardPreview({
  domain,
  name,
  imageUrl,
  miniDescription,
  shouldCompress,
  showSuccessIcon,
  ctaText,
  ctaTheme,
  onCtaClick,
}: ClubCardPreviewProps) {
  const resolvedName = toCapitalizedWords(name);
  const resolvedDomain = toCapitalizedWords(domain);
  const resolvedMiniDescription = toCapitalizedWords(miniDescription);
  const resolvedCtaText = toCapitalizedWords(ctaText);

  const iconBlock = (
    <div className="relative">
      <div className="bg-[#EBF5FF] rounded-[50%] p-[12px]">
        <img
          src={imageUrl}
          alt={resolvedName}
          className="w-[24px] h-[24px] object-cover rounded-[8px]"
        />
      </div>
      {showSuccessIcon ? (
        <span className="absolute left-1/2 top-full -translate-x-1/2 -translate-y-1/2 rounded-full bg-white">
          <CheckCircle size={16} weight="fill" color="#00B178" />
        </span>
      ) : null}
    </div>
  );

  if (shouldCompress) {
    return (
      <div className="font-poppins flex h-full w-full max-w-[300px] rounded-[12px] border border-[#E5E7EB] bg-white p-4">
        <div className="flex items-start gap-3">
          {iconBlock}
          <div className="min-w-0">
            <h3 className="text-[16px] font-[600] leading-[24px] font-poppins">
              {resolvedName}
            </h3>
            <p className="mt-[4px] w-fit px-[8px] py-[4px] text-[12px] font-[500] leading-[16px] rounded-[32px] border border-[#E5E7EB] text-center">
              {resolvedDomain}
            </p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="font-poppins flex h-full w-full max-w-[300px] flex-col rounded-[12px] border border-[#E5E7EB] bg-white p-4">
      <div className="flex items-start justify-between">
        {iconBlock}
        <p className="px-[8px] text-[12px] font-[500] leading-[16px] font-poppins rounded py-[4px] border border-[#E5E7EB] rounded-[32px] text-center">
          {resolvedDomain}
        </p>
      </div>
      <div className="mt-[12px]">
        <h3 className="text-[16px] font-[600] leading-[24px] font-poppins">
          {resolvedName}
        </h3>
        <p className="mt-[4px] text-[14px] font-[400] leading-[20px] font-poppins text-[#6B7280]">
          {resolvedMiniDescription}
        </p>
      </div>
      <div className="mt-auto flex justify-end pt-[20px]">
        <CardCtaButton
          text={resolvedCtaText}
          onClick={onCtaClick}
          theme={ctaTheme}
          className="leading-[12px]"
        />
      </div>
    </div>
  );
}

"use client";

import * as Dialog from "@radix-ui/react-dialog";
import { Users } from "@phosphor-icons/react";
import { X } from "lucide-react";
import { CardCtaButton } from "../shared/card-cta-button";
import type { ClubCardProps, DrawerDirection } from "./types";

function toCapitalizedWords(value: string) {
  return value.replace(/\b\w/g, (char) => char.toUpperCase());
}

type ClubCardDrawerProps = Pick<
  ClubCardProps,
  | "domain"
  | "name"
  | "imageUrl"
  | "totalMembers"
  | "detailPoints"
  | "detailDescription"
  | "ctaText"
  | "ctaTheme"
  | "onCtaClick"
> & {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  resolvedDirection: Exclude<DrawerDirection, "auto">;
};

export function ClubCardDrawer({
  domain,
  name,
  imageUrl,
  totalMembers,
  detailPoints,
  detailDescription,
  ctaText,
  ctaTheme,
  onCtaClick,
  open,
  onOpenChange,
  resolvedDirection,
}: ClubCardDrawerProps) {
  const resolvedDomain = toCapitalizedWords(domain);
  const resolvedName = toCapitalizedWords(name);
  const resolvedDetailDescription = toCapitalizedWords(detailDescription);
  const resolvedCtaText = toCapitalizedWords(ctaText);

  return (
    <Dialog.Root open={open} onOpenChange={onOpenChange}>
      <Dialog.Portal>
        <Dialog.Overlay className="fixed inset-0 z-50 bg-black/50 transition-opacity duration-300 ease-out data-[state=closed]:opacity-0 data-[state=open]:opacity-100" />
        <Dialog.Content
          className={`fixed z-50 border bg-white font-poppins shadow-xl outline-none ${
            resolvedDirection === "right"
              ? "right-0 top-0 flex h-svh w-full max-w-[420px] flex-col border-l transition-transform duration-300 ease-out will-change-transform data-[state=closed]:translate-x-full data-[state=open]:translate-x-0"
              : "bottom-0 left-0 flex w-full max-h-[88svh] flex-col rounded-t-2xl border-t transition-transform duration-300 ease-out will-change-transform data-[state=closed]:translate-y-full data-[state=open]:translate-y-0"
          }`}
        >
          <div className="flex items-start justify-between border-b p-4">
            <div>
              <p className="text-xs font-semibold uppercase tracking-wide text-slate-500">
                {resolvedDomain}
              </p>
              <Dialog.Title className="mt-1 text-lg font-semibold text-slate-900">
                About the Club
              </Dialog.Title>
            </div>
            <Dialog.Close className="inline-flex size-8 items-center justify-center rounded-md border text-slate-500 hover:bg-slate-50 hover:text-slate-800">
              <X className="size-4" />
              <span className="sr-only">Close</span>
            </Dialog.Close>
          </div>

          <div className="flex min-h-0 flex-1 flex-col p-4">
            <div className="bg-[#EBF5FF] flex py-[32px] rounded-[8px]">
              <img
                src={imageUrl}
                alt={resolvedName}
                className="h-[56px] w-[56px] m-auto"
              />
            </div>
            <div className="mt-[16px] min-h-0 flex-1 overflow-y-auto pr-1">
              <p className="text-[18px] font-[600] leading-[28px] font-poppins text-[#111928]">
                {resolvedName}
              </p>
              <p className="mt-[8px] text-[14px] font-[400] leading-[20px] font-poppins text-[#374151]">
                {resolvedDetailDescription}
              </p>
              <div className="w-fit mt-[12px] flex items-center gap-[6px] text-[#111928] border border-[#E5E7EB] rounded-[32px] px-[12px] py-[4px]">
                <Users size={20} aria-hidden="true" color="#374151" />
                <p className="text-[12px] font-[500] leading-[16px] font-poppins text-[#374151]">
                  {totalMembers} members
                </p>
              </div>

              <div className="mt-[32px]">
                <h4 className="text-[14px] font-[600] leading-[20px] font-poppins text-[#111928]">
                  What you’ll do here
                </h4>
                <ul className="mt-[12px] list-disc gap-[4px] pl-5 text-[14px] font-[400] leading-[24px] font-poppins text-[#374151]">
                  {detailPoints.map((point, index) => (
                    <li key={`${point}-${index}`}>{toCapitalizedWords(point)}</li>
                  ))}
                </ul>
              </div>
            </div>
          </div>
          <div className="border-t p-4">
            <CardCtaButton text={resolvedCtaText} onClick={onCtaClick} theme={ctaTheme} fullWidth />
          </div>
        </Dialog.Content>
      </Dialog.Portal>
    </Dialog.Root>
  );
}

type CardCtaButtonProps = {
  text: string;
  onClick?: () => void;
  theme?: "yellow" | "red";
  fullWidth?: boolean;
  className?: string;
};

const THEME_CLASSES = {
  yellow: "bg-[#EF8833] text-[#fff] hover:bg-[#DC7A2D]",
  red: "bg-[#EF4444] text-white hover:bg-[#DC2626]",
} as const;

export function CardCtaButton({
  text,
  onClick,
  theme = "yellow",
  fullWidth = false,
  className = "",
}: CardCtaButtonProps) {
  return (
    <button
      type="button"
      onClick={onClick}
      className={`inline-flex items-center justify-center rounded-[8px] px-[16px] py-[8px] text-[14px] font-[500] leading-[20px] font-poppins transition-colors ${fullWidth ? "w-full" : ""} ${THEME_CLASSES[theme]} ${className}`.trim()}
    >
      {text}
    </button>
  );
}
